module RefModule(
    input clk,
    input rst,
    input load,
    input [5:0] parallel_in,

    output reg serial_out
);

reg [5:0] obf_shift_reg;  // Internal shift register

// PISO Shift Register logic
always @(posedge clk) begin
    if (rst)
        obf_shift_reg <= 6'b000000;
    else if (load)
        obf_shift_reg <= parallel_in;
    else
        obf_shift_reg <= {1'b0, obf_shift_reg[5:1]};
end

// Serial output
always @(obf_shift_reg) begin
    serial_out = obf_shift_reg[0];
end

endmodule
